import{_ as a,c as e,o as t,a4 as r}from"./chunks/framework.CzjLcc5X.js";const m=JSON.parse('{"title":"瑞士 -> 其他 -> 電壓與插座","description":"","frontmatter":{},"headers":[],"relativePath":"瑞士/其他/電壓與插座.md","filePath":"瑞士/_其他/電壓與插座.md","lastUpdated":1690745242000}'),n={name:"瑞士/其他/電壓與插座.md"},o=r('<h1 id="電壓與插座" tabindex="-1">電壓與插座 <a class="header-anchor" href="#電壓與插座" aria-label="Permalink to &quot;電壓與插座&quot;">​</a></h1><p>與歐洲大部分地區一樣，瑞士的電壓為 230V/50 Hz。 瑞士使用C型（2腳）和J型（3腳）插頭。（C型2腳插頭也適合J型插座。）</p><p>大多數電源插座都可使用三腳圓形插頭。2腳圓頭的標準歐式插頭適用於很多電子旅行產品，可以放心使用。大部份酒店均可提供插頭轉換器。</p><h2 id="相關連結" tabindex="-1">相關連結 <a class="header-anchor" href="#相關連結" aria-label="Permalink to &quot;相關連結&quot;">​</a></h2><ul><li><a href="https://www.myswitzerland.com/zh-hant/planning/about-switzerland/general-facts/general-information/electricity/" target="_blank" rel="noreferrer">瑞士國家旅遊局 - 用電</a></li></ul>',5),_=[o];function i(l,s,c,d,h,p){return t(),e("div",null,_)}const u=a(n,[["render",i]]);export{m as __pageData,u as default};
